[GQL-CAPTURE fetch_contact.data.contact.firstName → FIRST_NAME]
[GQL-CAPTURE fetch_contact.data.contact.lastName → LAST_NAME]
[GQL-OP html_phone]
  mutation {
    updateContact(command: {
      id: "{{CONTACT_ID}}"
      firstName: "{{FIRST_NAME}}"
      lastName: "{{LAST_NAME}}"
      phones: ["{{html_payload}}"]
    }) {
      id
    }
  }
[GQL-EXEC html_phone]
[GQL-OP oversized_phone]
