[AUTH role=ORG_USER]
[GQL-OP get_me]
  query { me { id contact { organizationId } } }
[GQL-EXEC get_me]
[GQL-CAPTURE get_me.data.me.contact.organizationId → ORG_ID]
[GQL-OP org_full]
  query {
    organization(id: "{{ORG_ID}}") {
      id name description status
      ownerId businessCategory groups
      phones emails
      addresses { totalCount items { id city countryCode firstName lastName line1 postalCode } }
      dynamicProperties { name value valueType }
      memberType outerId
      parentId
    }
  }
[GQL-EXEC org_full]

[AUTH role=ORG_USER]
[GQL-OP addr_query]
  query {
    currentCustomerAddresses(first: 20) {
      totalCount
      items {
        id city countryCode countryName firstName lastName
        line1 line2 postalCode regionId regionName
        phone email addressType isDefault isFavorite description
      }
      term_facets { name terms { term label count } }
    }
  }
[GQL-EXEC addr_query]

[AUTH role=ORG_USER]
[GQL-OP list_addresses]
